export type SportCategory = 'cross_country' | 'biathlon' | 'football';
export type SourceKey = 'NRK' | 'TV 2' | 'Viaplay' | 'NRK Radio' | 'TWE';

export interface SportEvent {
  idx: number;
  title: string;
  category: SportCategory;
  channel: string;
  date: string; // YYYY-MM-DD
  startTime: string; // HH:MM
  /** Unix seconds. */
  timestamp: number;
  streamUrl?: string;
  radioUrl?: string;
  competition?: 'UCL' | 'PL' | 'LL';
}

export interface SourceInfo {
  label: string;
  url: string | null;
  cls: string;
}

