export const STREAMS: Record<SourceKey, SourceInfo> = {
  'NRK':       { label: 'NRK TV',          url: null,                                          cls: 'nrk' },
  'TV 2':      { label: 'TV 2 direkte',    url: 'https://tv2.no/direkte/',                    cls: 'tv2' },
  'Viaplay':   { label: 'Viaplay Sport',   url: 'https://viaplay.no/sport/live',              cls: 'viaplay' },
  'NRK Radio': { label: 'NRK Sport Radio', url: 'https://radio.nrk.no/direkte/sport',         cls: 'radio' },
  'TWE':       { label: 'TWE Langrenn',    url: 'https://twe.no/channelPlay/TnNo4034',        cls: 'twe' },
};

/** Returns the playable source list for an event (channel + cross-country auto-adds TWE). */
export function getSources(event: SportEvent): SourceKey[] {
  const sources = event.channel
    .split(' + ')
    .map((s) => s.trim())
    .filter((s): s is SourceKey => s in STREAMS);
  if (event.category === 'cross_country' && !sources.includes('TWE')) sources.push('TWE');
  return sources;
}

/** Resolves the URL to open for a given source on a given event. */
export function resolveUrl(source: SourceKey, event: SportEvent): string {
  if (source === 'NRK') return event.streamUrl ?? 'https://tv.nrk.no/sport';
  if (source === 'Viaplay') return event.streamUrl ?? STREAMS.Viaplay.url ?? '#';
  if (source === 'TV 2') return event.streamUrl ?? STREAMS['TV 2'].url ?? '#';
  if (source === 'NRK Radio') return event.radioUrl ?? STREAMS['NRK Radio'].url ?? '#';
  return STREAMS[source].url ?? '#';
}
